import React from 'react';
import { Line } from 'react-chartjs-2';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
  Filler
} from 'chart.js';

ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
  Filler
);

const DashboardView = ({ transactions }) => {
  const stats = [
    { label: 'TOTAL TRANSACTIONS', value: '9,060', delta: '+12.3% vs last period', icon: '📈', color: '#10b981' },
    { label: 'FRAUD DETECTED', value: '83', delta: '-8.1% vs last period', icon: '🛡️', color: '#ef4444' },
    { label: 'BLOCKED', value: '47', delta: '+2.4% vs last period', icon: '🚫', color: '#3b82f6' }
  ];

  const chartData = {
    labels: ['00:00', '02:00', '04:00', '06:00', '08:00', '10:00', '12:00', '14:00', '16:00', '18:00', '20:00', '22:00'],
    datasets: [
      {
        label: 'Legitimate',
        data: [400, 200, 150, 300, 700, 1100, 1400, 1300, 1100, 800, 500, 300],
        borderColor: '#10b981',
        backgroundColor: 'rgba(16, 185, 129, 0.1)',
        fill: true,
        tension: 0.4,
        pointRadius: 0
      },
      {
        label: 'Fraudulent',
        data: [10, 5, 2, 8, 15, 25, 30, 28, 22, 18, 12, 8],
        borderColor: '#ef4444',
        backgroundColor: 'rgba(239, 68, 68, 0.1)',
        fill: true,
        tension: 0.4,
        pointRadius: 0
      }
    ]
  };

  const chartOptions = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      legend: {
        position: 'bottom',
        labels: { color: '#94a3b8', usePointStyle: true, pointStyle: 'circle' }
      }
    },
    scales: {
      x: { grid: { display: false }, ticks: { color: '#64748b' } },
      y: { grid: { color: '#1e293b' }, ticks: { color: '#64748b' } }
    }
  };

  const recentAlerts = [
    { title: 'High Amount Threshold', desc: 'Transaction amount exceeds $2,000 threshold for new account.', time: '08:23', type: 'high', icon: '⚠️' },
    { title: 'Velocity Check', desc: 'Multiple high-value transactions within 10 minutes from same account.', time: '08:15', type: 'critical', icon: '🚨' },
    { title: 'Geo-Location Anomaly', desc: 'Wire transfer to high-risk region detected.', time: '08:05', type: 'medium', icon: '📍' }
  ];

  return (
    <div style={{ padding: '2rem' }}>
      <h2 style={{ fontSize: '1.5rem', fontWeight: 'bold', marginBottom: '0.5rem' }}>Fraud Monitoring Dashboard</h2>
      <p style={{ color: '#94a3b8', marginBottom: '2rem' }}>Real-time overview of transaction activity and threat detection</p>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '1.5rem', marginBottom: '2rem' }}>
        {stats.map(stat => (
          <div key={stat.label} style={{ backgroundColor: '#1e293b', padding: '1.5rem', borderRadius: '1rem', border: '1px solid #334155' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '1rem' }}>
              <p style={{ fontSize: '0.75rem', fontWeight: 'bold', color: '#94a3b8', letterSpacing: '0.05em' }}>{stat.label}</p>
              <span style={{ fontSize: '1.25rem' }}>{stat.icon}</span>
            </div>
            <h3 style={{ fontSize: '2rem', fontWeight: 'bold', marginBottom: '0.5rem' }}>{stat.value}</h3>
            <p style={{ fontSize: '0.875rem', color: stat.delta.startsWith('+') ? '#10b981' : '#ef4444' }}>{stat.delta}</p>
          </div>
        ))}
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '2fr 1fr', gap: '1.5rem' }}>
        <div style={{ backgroundColor: '#1e293b', padding: '1.5rem', borderRadius: '1rem', border: '1px solid #334155' }}>
          <h3 style={{ fontSize: '1rem', fontWeight: 'bold', marginBottom: '1.5rem' }}>Transaction Volume (24h)</h3>
          <div style={{ height: '300px' }}>
            <Line data={chartData} options={chartOptions} />
          </div>
        </div>

        <div style={{ backgroundColor: '#1e293b', padding: '1.5rem', borderRadius: '1rem', border: '1px solid #334155' }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '1.5rem' }}>
            <h3 style={{ fontSize: '1rem', fontWeight: 'bold' }}>Recent Alerts</h3>
            <span style={{ backgroundColor: '#ef4444', color: 'white', padding: '0.25rem 0.75rem', borderRadius: '1rem', fontSize: '0.75rem' }}>4 Active</span>
          </div>
          <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
            {recentAlerts.map((alert, i) => (
              <div key={i} style={{ padding: '1rem', backgroundColor: '#0f172a', borderRadius: '0.75rem', border: '1px solid #1e293b' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '0.5rem' }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                    <span>{alert.icon}</span>
                    <p style={{ fontSize: '0.875rem', fontWeight: 'bold' }}>{alert.title}</p>
                  </div>
                  <span style={{ 
                    fontSize: '0.75rem', 
                    padding: '0.125rem 0.5rem', 
                    borderRadius: '0.25rem',
                    backgroundColor: alert.type === 'critical' ? 'rgba(239, 68, 68, 0.1)' : 'rgba(245, 158, 11, 0.1)',
                    color: alert.type === 'critical' ? '#ef4444' : '#f59e0b'
                  }}>{alert.type}</span>
                </div>
                <p style={{ fontSize: '0.75rem', color: '#94a3b8', marginBottom: '0.5rem' }}>{alert.desc}</p>
                <p style={{ fontSize: '0.75rem', color: '#64748b' }}>{alert.time}</p>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

export default DashboardView;
